{
  "asset": {
    "brand": "enovate3d",
    "model": "EP400-SP",
    "category": "Multifunctional Solder Paste Printer"
  }
}

{
  "asset": {
    "manufacturer": "Xihu Future Intelligent Manufacturing",
    "brand": "enovate3d",
    "model": "EP400-SP",
    "category": "Multifunctional Solder Paste Printer"
  }
}

{
  "capabilities": {
    "min_jet_print_dot_diameter_um": 250,
    "min_dip_transfer_dot_diameter_um": 100,
    "max_cavity_depth_mm": 6
  },
  "unit_normalization": {
    "dot_diameter": "\u03bcm",
    "depth": "mm"
  }
}

{
  "capabilities": {
    "max_conveyor_rail_width_mm": 350,
    "max_motion_acceleration_g": 3
  },
  "interfaces": {
    "file_formats_supported": [
      "Gerber",
      "DXF"
    ],
    "line_interface_standards": [
      "SMEMA"
    ]
  },
  "key_features": [
    "Adjustable conveyor rail width supporting carrier transfer",
    "Supports file import and parameterized programming workflow",
    "High motion acceleration for higher productivity",
    "SMEMA-compatible line docking"
  ]
}

{
  "specs": {
    "motion_system": {
      "travel_range_mm": {
        "x": 450,
        "y": 650,
        "z1": 20,
        "z2": 50
      },
      "max_speed_mm_per_s": {
        "x": 1000,
        "y": 1000,
        "z": 300
      },
      "positioning_accuracy_um": {
        "x_y": 10,
        "z1_z2": 5
      }
    }
  },
  "unit_normalization": {
    "travel": "mm",
    "speed": "mm/s",
    "accuracy": "\u03bcm"
  }
}

{
  "specs": {
    "printing_system": {
      "jet_print_module": {
        "valve_type": "Piezoelectric needle-impact jet valve",
        "nozzle_inner_diameter_range_mm": {
          "min": 0.07,
          "max": 0.4
        }
      }
    }
  },
  "unit_normalization": {
    "diameter": "mm"
  }
}

{
  "specs": {
    "printing_system": {
      "dip_transfer_module": {
        "type": "Contact dip-and-transfer needle",
        "needle_diameter_range_mm": {
          "min": 0.05,
          "max": 0.25
        }
      }
    }
  },
  "unit_normalization": {
    "diameter": "mm"
  }
}

{
  "specs": {
    "fixture_system": {
      "fixture_size_range_mm": {
        "min": {
          "x": 90,
          "y": 90
        },
        "max": {
          "x": 210,
          "y": 350
        }
      },
      "adjustment": "continuous",
      "max_payload_kg": 3
    }
  },
  "unit_normalization": {
    "size": "mm",
    "payload": "kg"
  }
}

{
  "specs": {
    "auxiliary_system": {
      "vision": {
        "camera_resolution_mp": 5,
        "fov_mm": {
          "x": 5.9,
          "y": 4.4
        },
        "supports_fiducial_alignment": true
      }
    }
  },
  "unit_normalization": {
    "fov": "mm"
  }
}

{
  "specs": {
    "auxiliary_system": {
      "height_following": {
        "sensor_type": "Coaxial laser displacement sensor",
        "measurement_accuracy_um_lte": 25,
        "purpose": "Needle height following during printing"
      }
    }
  },
  "unit_normalization": {
    "accuracy": "\u03bcm"
  }
}

{
  "specs": {
    "auxiliary_system": {
      "cleaning": {
        "vacuum_cleaning": true,
        "dry_wipe_cleaning": true
      }
    }
  }
}

{
  "specs": {
    "auxiliary_system": {
      "metering_or_weighing": {
        "resolution_mg": 0.1
      },
      "cleanroom": {
        "ffu_grade": "Dry-grade FFU"
      }
    }
  },
  "unit_normalization": {
    "resolution": "mg"
  }
}

{
  "capabilities": {
    "throughput_pads_per_s": 5,
    "throughput_reference": "0402 pad jetting example"
  },
  "unit_normalization": {
    "throughput": "pads/s"
  }
}

{
  "capabilities": {
    "min_jet_print_dot_diameter_um": 250,
    "min_dip_transfer_dot_diameter_um": 100,
    "solder_paste_type_example": "Type7"
  },
  "unit_normalization": {
    "dot_diameter": "\u03bcm"
  }
}

{
  "specs": {
    "installation": {
      "machine_dimensions_mm": {
        "w": 1480,
        "d": 1480,
        "h": 2000
      },
      "machine_weight_kg": 1500
    }
  },
  "unit_normalization": {
    "dimensions": "mm",
    "weight": "kg"
  }
}

{
  "specs": {
    "installation": {
      "power": {
        "voltage_vac": 380,
        "frequency_hz": 50,
        "power_kw": 5
      }
    }
  },
  "unit_normalization": {
    "voltage": "VAC",
    "frequency": "Hz",
    "power": "kW"
  }
}

{
  "specs": {
    "installation": {
      "environment": {
        "temperature_c": {
          "nominal": 22,
          "tolerance": 2
        },
        "humidity_percent_rh_lt": 80
      },
      "air_supply": {
        "pressure_mpa": {
          "min": 0.6,
          "max": 0.8
        }
      }
    }
  },
  "unit_normalization": {
    "temperature": "\u00b0C",
    "humidity": "%RH",
    "pressure": "MPa"
  }
}

{
  "applications": {
    "workpieces": [
      "PCBs of various shapes and sizes",
      "Irregular/complex components",
      "Complex pad layout scenarios"
    ]
  }
}

{
  "process_recommendation": {
    "materials": [
      "SAC305 solder paste",
      "SnPb solder paste"
    ],
    "printing_modes": [
      "Jet forming",
      "Dip transfer"
    ]
  }
}

{
  "interfaces": {
    "automation": [
      "Software-driven automated operation",
      "CAD-data-driven workflow",
      "Parameterized programming workflow"
    ],
    "file_formats_supported": [
      "Gerber",
      "DXF"
    ]
  }
}
